def calculate_eradicability_score(has_secondary_host, clear_identification, accurate_diagnostic, sufficient_money, sufficient_political_support):
    # Assign scores based on factors (1 for yes, 0 for no)
    scores = {
        'secondary_host': 1 if has_secondary_host else 0,
        'clear_identification': 1 if clear_identification else 0,
        'accurate_diagnostic': 1 if accurate_diagnostic else 0,
        'sufficient_money': 1 if sufficient_money else 0,
        'sufficient_political_support': 1 if sufficient_political_support else 0
    }

    # Calculate total score (higher is more eradicable)
    total_score = sum(scores.values())
    eradicability = total_score / len(scores)  # Normalize to 0-1

    # Determine eradicability category
    if eradicability == 1.0:
        category = "Highly eradicable"
    elif eradicability >= 0.6:
        category = "Moderately eradicable"
    elif eradicability >= 0.4:
        category = "Low eradicability"
    else:
        category = "Not eradicable"

    return {
        'score': eradicability,
        'category': category,
        'details': scores
    }

# Example usage:
print(calculate_eradicability_score(
    has_secondary_host=False,
    clear_identification=True,
    accurate_diagnostic=True,
    sufficient_money=True,
    sufficient_political_support=True
))
# Output: {'score': 0.8, 'category': 'Moderately eradicable', 'details': {'secondary_host': 0, 'clear_identification': 1, 'accurate_diagnostic': 1, 'sufficient_money': 1, 'sufficient_political_support': 1}}
